import React, { useState, useEffect, useMemo, useRef } from 'react';
import {
CheckCircle2, Circle, Trophy, BookOpen, RotateCcw,
Activity, Lightbulb, X, BarChart2, Calendar, TrendingUp,
PieChart, Heart, ArrowLeft, Save, Moon, Sun, Clock, Zap, Smile, Cloud, Loader2, Database, AlertCircle, Check, BedDouble, Eye, EyeOff, Sparkles, ChevronDown, Users, MessageSquare, Flame, Brain, Scale, LogIn, UserPlus, Menu, Mail, Lock, User as UserIcon, LogOut, Facebook, Camera
} from 'lucide-react';
import { AreaChart, Area, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, Radar, ResponsiveContainer, CartesianGrid, XAxis, YAxis, Tooltip, BarChart, Bar, Legend } from 'recharts';

// --- FIREBASE CONFIGURATION & SETUP ---
import { initializeApp } from 'firebase/app';
import {
getAuth,
onAuthStateChanged,
signInAnonymously,
signInWithCustomToken,
createUserWithEmailAndPassword,
signInWithEmailAndPassword,
updateProfile,
signOut,
GoogleAuthProvider,
FacebookAuthProvider,
signInWithPopup,
linkWithCredential,
EmailAuthProvider
} from 'firebase/auth';
import {
getFirestore,
collection,
doc,
getDoc,
setDoc,
getDocs,
writeBatch
} from 'firebase/firestore';

// Función inteligente para obtener la config de Firebase
// Funciona tanto en Local/Vercel (Vite env vars) como en el entorno de Preview
const getFirebaseConfig = () => {
try {
// 1. Intenta leer variables de entorno de Vite (Para Vercel/Local)
// Nota: import.meta.env puede no estar disponible en todos los entornos de preview, por eso el try-catch
if (import.meta && import.meta.env && import.meta.env.VITE_FIREBASE_API_KEY) {
return {
apiKey: import.meta.env.VITE_FIREBASE_API_KEY,
authDomain: import.meta.env.VITE_FIREBASE_AUTH_DOMAIN,
projectId: import.meta.env.VITE_FIREBASE_PROJECT_ID,
storageBucket: import.meta.env.VITE_FIREBASE_STORAGE_BUCKET,
messagingSenderId: import.meta.env.VITE_FIREBASE_MESSAGING_SENDER_ID,
appId: import.meta.env.VITE_FIREBASE_APP_ID
};
}
} catch (e) {
// Ignorar error si import.meta no existe
}

// 2. Fallback para el entorno de Preview actual (este chat)
if (typeof __firebase_config !== 'undefined') {
return JSON.parse(__firebase_config);
}

console.warn("No se encontró configuración de Firebase.");
return null;
};

const firebaseConfig = getFirebaseConfig();
// Inicializamos solo si hay config
const app = firebaseConfig ? initializeApp(firebaseConfig) : null;
const auth = app ? getAuth(app) : null;
const db = app ? getFirestore(app) : null;

// App ID dinámico
const getAppId = () => {
if (typeof __app_id !== 'undefined') return __app_id;
return 'personal-canvas-final'; // ID por defecto para producción
};
const appId = getAppId();

// ==========================================
// 1. COMPONENTES UI
// ==========================================

const Toast = ({ message, type, onClose }) => {
useEffect(() => {
const timer = setTimeout(onClose, 3000);
return () => clearTimeout(timer);
}, [onClose]);

return (
<div className={`fixed bottom-24 right-4 z-[90] px-6 py-3 rounded-xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-bottom-5 fade-in duration-300 ${type === 'success' ? 'bg-emerald-600 text-white' : 'bg-red-600 text-white'}`}>
{type === 'success' ? <CheckCircle2 size={20} /> : <AlertCircle size={20} />}
<span className="font-medium">{message}</span>
</div>
);
};

// --- AUTH MODAL COMPONENT (POP UP) ---
const AuthModal = ({ isOpen, onClose }) => {
const [isLogin, setIsLogin] = useState(true);
const [email, setEmail] = useState('');
const [password, setPassword] = useState('');
const [name, setName] = useState('');
const [loading, setLoading] = useState(false);
const [error, setError] = useState(null);

useEffect(() => {
if (isOpen) {
setError(null);
setLoading(false);
setPassword('');
}
}, [isOpen]);

if (!isOpen) return null;

const handleSubmit = async (e) => {
e.preventDefault();
if (!auth) return;
setLoading(true);
setError(null);

try {
if (isLogin) {
await signInWithEmailAndPassword(auth, email, password);
} else {
if (auth.currentUser && auth.currentUser.isAnonymous) {
const credential = EmailAuthProvider.credential(email, password);
await linkWithCredential(auth.currentUser, credential);
await updateProfile(auth.currentUser, { displayName: name });
} else {
const userCredential = await createUserWithEmailAndPassword(auth, email, password);
await updateProfile(userCredential.user, { displayName: name });
}
}
onClose();
} catch (err) {
console.error(err);
let msg = "Error de autenticación.";
if (err.code === 'auth/email-already-in-use') msg = "Este correo ya está registrado. Intenta iniciar sesión.";
if (err.code === 'auth/credential-already-in-use') msg = "Esta cuenta ya existe.";
if (err.code === 'auth/invalid-credential' || err.code === 'auth/user-not-found' || err.code === 'auth/wrong-password') msg = "Credenciales incorrectas.";
if (err.code === 'auth/weak-password') msg = "La contraseña es muy débil (mínimo 6 caracteres).";
setError(msg);
} finally {
setLoading(false);
}
};

const handleSocialLogin = async (providerName) => {
if (!auth) return;
setLoading(true);
setError(null);
try {
let provider;
if (providerName === 'google') {
provider = new GoogleAuthProvider();
} else {
provider = new FacebookAuthProvider();
}

if (auth.currentUser && auth.currentUser.isAnonymous) {
try {
await linkWithCredential(auth.currentUser, provider);
} catch (linkError) {
if (linkError.code === 'auth/credential-already-in-use') {
await signInWithPopup(auth, provider);
} else {
throw linkError;
}
}
} else {
await signInWithPopup(auth, provider);
}
onClose();
} catch (err) {
console.error("Social Auth Error:", err);
let msg = `No se pudo iniciar con ${providerName}.`;
if (err.code === 'auth/account-exists-with-different-credential') msg = "Ya existe una cuenta con el mismo email pero diferentes credenciales.";
if (err.code === 'auth/popup-closed-by-user') msg = "Inicio de sesión cancelado.";
if (err.code === 'auth/credential-already-in-use') msg = "Esta cuenta social ya está vinculada a otro usuario.";
setError(msg);
} finally {
setLoading(false);
}
};

return (
<div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md animate-in fade-in duration-200">
<div
className="bg-white rounded-3xl shadow-2xl max-w-sm w-full overflow-hidden relative animate-in zoom-in-95 duration-200"
onClick={(e) => e.stopPropagation()}
>
<button
onClick={onClose}
className="absolute top-4 right-4 z-10 p-2 bg-slate-100 text-slate-500 rounded-full hover:bg-slate-200 hover:text-slate-800 transition-colors"
type="button"
>
<X size={20} />
</button>

<div className="p-8 pt-10">
<div className="text-center mb-6">
<h2 className="text-2xl font-bold text-slate-900">{isLogin ? 'Bienvenido' : 'Crear Cuenta'}</h2>
<p className="text-slate-500 text-sm mt-2 leading-relaxed">
{isLogin ? 'Ingresa para sincronizar tus datos.' : 'Regístrate para guardar tu progreso actual en la nube.'}
</p>
</div>

{error && (
<div className="mb-6 p-3 bg-red-50 border border-red-100 text-red-600 text-xs font-medium rounded-xl flex items-start gap-2">
<AlertCircle size={16} className="shrink-0 mt-0.5" /> <span>{error}</span>
</div>
)}

<form onSubmit={handleSubmit} className="space-y-4">
{!isLogin && (
<div className="space-y-1">
<label className="text-xs font-bold text-slate-700 ml-1 uppercase tracking-wider">Nombre</label>
<div className="relative">
<UserIcon className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
<input
type="text"
required
value={name}
onChange={(e) => setName(e.target.value)}
className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all placeholder:text-slate-400"
placeholder="Tu nombre"
/>
</div>
</div>
)}

<div className="space-y-1">
<label className="text-xs font-bold text-slate-700 ml-1 uppercase tracking-wider">Correo</label>
<div className="relative">
<Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
<input
type="email"
required
value={email}
onChange={(e) => setEmail(e.target.value)}
className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all placeholder:text-slate-400"
placeholder="ejemplo@correo.com"
/>
</div>
</div>

<div className="space-y-1">
<label className="text-xs font-bold text-slate-700 ml-1 uppercase tracking-wider">Contraseña</label>
<div className="relative">
<Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
<input
type="password"
required
value={password}
onChange={(e) => setPassword(e.target.value)}
className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all placeholder:text-slate-400"
placeholder="••••••••"
/>
</div>
</div>

<button
type="submit"
disabled={loading}
className="w-full mt-2 py-3.5 bg-indigo-600 text-white font-bold rounded-xl shadow-lg shadow-indigo-500/30 hover:bg-indigo-700 hover:shadow-indigo-600/40 active:scale-[0.98] transition-all flex justify-center items-center gap-2"
>
{loading && !error ? <Loader2 size={20} className="animate-spin" /> : (isLogin ? 'Iniciar Sesión' : 'Registrarse Gratis')}
</button>
</form>

{/* Social Logins */}
<div className="my-6 flex items-center gap-3">
<div className="h-px bg-slate-200 flex-1"></div>
<span className="text-xs font-medium text-slate-400 uppercase tracking-wider">O continúa con</span>
<div className="h-px bg-slate-200 flex-1"></div>
</div>

<div className="grid grid-cols-2 gap-3">
<button
type="button"
onClick={() => handleSocialLogin('google')}
className="flex items-center justify-center gap-2 py-2.5 px-4 bg-white border border-slate-200 rounded-xl text-slate-700 text-sm font-semibold hover:bg-slate-50 hover:border-slate-300 transition-all shadow-sm active:scale-95"
>
<svg className="w-5 h-5" viewBox="0 0 24 24">
<path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" />
<path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" />
<path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" />
<path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" />
</svg>
Google
</button>

<button
type="button"
onClick={() => handleSocialLogin('facebook')}
className="flex items-center justify-center gap-2 py-2.5 px-4 bg-[#1877F2] border border-[#1877F2] rounded-xl text-white text-sm font-semibold hover:bg-[#166fe5] transition-all shadow-sm shadow-blue-500/20 active:scale-95"
>
<Facebook size={20} fill="currentColor" strokeWidth={0} />
Facebook
</button>
</div>

<div className="mt-8 text-center pt-6 border-t border-slate-100">
<p className="text-sm text-slate-500">
{isLogin ? "¿Nuevo aquí? " : "¿Ya tienes cuenta? "}
<button
onClick={() => { setIsLogin(!isLogin); setError(null); }}
className="text-indigo-600 font-bold hover:text-indigo-700 transition-colors ml-1"
>
{isLogin ? "Crea una cuenta" : "Inicia sesión"}
</button>
</p>
</div>
</div>
</div>
</div>
);
};

const Modal = ({ isOpen, title, children, onConfirm, onCancel, confirmText = "Confirmar", cancelText = "Cancelar" }) => {
if (!isOpen) return null;
return (
<div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/70 backdrop-blur-sm animate-in fade-in duration-200">
<div className="bg-white rounded-2xl shadow-2xl max-w-sm w-full overflow-hidden animate-in zoom-in-95 duration-200">
<div className="p-6">
<h3 className="text-lg font-bold text-slate-900 mb-2">{title}</h3>
<div className="text-slate-600 text-sm">{children}</div>
</div>
<div className="bg-slate-50 p-4 flex justify-end gap-3">
<button onClick={onCancel} className="px-4 py-2 text-slate-600 font-medium hover:bg-slate-200 rounded-lg transition">{cancelText}</button>
<button onClick={onConfirm} className="px-4 py-2 bg-red-600 text-white font-medium hover:bg-red-700 rounded-lg transition shadow-md hover:shadow-lg">{confirmText}</button>
</div>
</div>
</div>
);
};

const Card = ({ children, className = "" }) => (
<div className={`bg-slate-800 border border-slate-700 rounded-xl shadow-lg overflow-hidden ${className}`}>
{children}
</div>
);

const formatDateFriendly = (dateString) => {
if (!dateString) return "";
const [year, month, day] = dateString.split('-').map(Number);
const date = new Date(year, month - 1, day, 12, 0, 0);
return date.toLocaleDateString('es-ES', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
};

const getMonthName = (dateString) => {
const [year, month, day] = dateString.split('-').map(Number);
const date = new Date(year, month - 1, day);
return date.toLocaleDateString('es-ES', { month: 'long', year: 'numeric' });
};

// --- COMPANY HEADER COMPONENT ---
const CompanyHeader = ({ darkMode = false, onAuthClick, user }) => (
<div className={`w-full py-4 border-b ${darkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-200'} sticky top-0 z-30 transition-colors duration-300`}>
<div className="max-w-7xl mx-auto px-4 flex justify-between items-center">
{/* Logo & Company Name */}
<div className="flex items-center gap-3 group cursor-pointer">
<div className="bg-gradient-to-tr from-indigo-600 to-violet-600 p-2 rounded-lg text-white shadow-lg shadow-indigo-500/30 group-hover:scale-110 transition-transform duration-300">
<Activity size={24} />
</div>
<div>
<h1 className={`text-xl font-bold tracking-tight ${darkMode ? 'text-white' : 'text-slate-900'}`}>Surreal Horizons</h1>
<p className={`text-[10px] uppercase tracking-widest font-semibold ${darkMode ? 'text-slate-500' : 'text-slate-400'}`}>Personal Growth Platform</p>
</div>
</div>

{/* Login / Sign In / User Profile */}
<div className="flex items-center gap-3">
{user && !user.isAnonymous ? (
<div className={`flex items-center gap-3 px-1.5 py-1.5 pr-4 rounded-full border transition-all ${darkMode ? 'border-slate-700 bg-slate-800 text-slate-200' : 'border-slate-200 bg-slate-50 text-slate-700'}`}>
<div className="w-8 h-8 rounded-full bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center text-white text-xs font-bold shadow-md">
{user.displayName ? user.displayName[0].toUpperCase() : 'U'}
</div>
<div className="hidden md:flex flex-col">
<span className="text-xs font-bold leading-none">{user.displayName || 'Usuario'}</span>
<span className="text-[10px] opacity-70 leading-none mt-0.5">Pro Member</span>
</div>
<div className="h-4 w-[1px] bg-current opacity-20 mx-1"></div>
<button
onClick={() => auth && signOut(auth)}
className="text-xs hover:text-red-500 transition-colors p-1 rounded-full hover:bg-red-500/10"
title="Cerrar sesión"
>
<LogOut size={16} />
</button>
</div>
) : (
<>
<button
onClick={onAuthClick}
className={`hidden md:flex px-4 py-2 text-sm font-medium transition-colors ${darkMode ? 'text-slate-300 hover:text-white' : 'text-slate-600 hover:text-slate-900'}`}
>
Iniciar Sesión
</button>
<button
onClick={onAuthClick}
className={`flex items-center gap-2 px-4 py-2 rounded-full text-sm font-bold text-white shadow-md transition-all hover:shadow-lg active:scale-95 hover:translate-y-[-1px] ${darkMode ? 'bg-slate-700 hover:bg-slate-600' : 'bg-slate-900 hover:bg-slate-800'}`}
>
<UserPlus size={16} />
<span className="hidden md:inline">Registrarse</span>
<span className="md:hidden">Entrar</span>
</button>
</>
)}
</div>
</div>
</div>
);

// ==========================================
// 2. DATOS & RECURSOS
// ==========================================
const RESOURCES_DB = {
reading: [
{ title: "El Almohadón de Plumas (H. Quiroga)", url: "https://ciudadseva.com/texto/el-almohadon-de-plumas/", time: "8 min" },
{ title: "Continuidad de los Parques (J. Cortázar)", url: "https://ciudadseva.com/texto/continuidad-de-los-parques/", time: "3 min" }
],
exercise: [
{ title: "Rutina Cardio 30 min", url: "https://www.youtube.com/results?search_query=cardio+30+minutos+en+casa", type: "video" }
],
meditation: [
{ title: "Meditación Guiada 10 min", url: "https://www.youtube.com/results?search_query=meditacion+guiada+10+minutos", type: "video" }
],
water: { tip: "Consejo: Ten una botella de 1L en tu escritorio. Si la ves, beberás. Intenta terminarla antes de las 14:00." },
sleep: { tip: "Método 10-3-2-1: 10h antes sin cafeína, 3h sin comida, 2h sin trabajo, 1h sin pantallas." },
general: { tip: "Divide esta tarea en pasos de 2 minutos. ¿Cuál es la acción más pequeña que puedes tomar ahora mismo?" }
};

const DEFAULT_GOALS = [
{ id: 1, text: "Leer 15 páginas", category: "Intelectual", completed: false, resourceKey: 'reading' },
{ id: 2, text: "Ejercicio físico (30 min)", category: "Salud", completed: false, resourceKey: 'exercise' },
{ id: 3, text: "Meditar 10 min", category: "Espiritual", completed: false, resourceKey: 'meditation' },
{ id: 4, text: "Beber 2 litros de agua", category: "Salud", completed: false, resourceKey: 'water' },
{ id: 5, text: "Planificar el día siguiente", category: "General", completed: false, resourceKey: 'general' },
{ id: 6, text: "Llamar a un familiar/amigo", category: "Social", completed: false, resourceKey: 'general' },
{ id: 7, text: "Trabajo profundo (2 horas)", category: "Trabajo", completed: false, resourceKey: 'general' },
{ id: 8, text: "Sin azúcar añadido hoy", category: "Salud", completed: false, resourceKey: 'general' },
{ id: 9, text: "Estiramientos (10 min)", category: "Salud", completed: false, resourceKey: 'exercise' },
{ id: 10, text: "Revisar gastos/finanzas", category: "General", completed: false, resourceKey: 'general' },
{ id: 11, text: "Limpiar/Ordenar espacio", category: "General", completed: false, resourceKey: 'general' },
{ id: 12, text: "Ir a la cama a la hora prevista", category: "Salud", completed: false, resourceKey: 'sleep' },
{ id: 13, text: "Despertar sin posponer alarma", category: "General", completed: false, resourceKey: 'sleep' },
{ id: 14, text: "Desconexión de pantallas", category: "Salud", completed: false, resourceKey: 'sleep' },
{ id: 15, text: "Comer una pieza de fruta/verdura", category: "Salud", completed: false, resourceKey: 'general' },
{ id: 16, text: "Agradecer 3 cosas del día", category: "Espiritual", completed: false, resourceKey: 'general' },
{ id: 17, text: "Aprender algo nuevo", category: "Intelectual", completed: false, resourceKey: 'general' }
];

const REFLECTIONS_MOCK = [
"Hoy me sentí con mucha energía y motivación.",
"Dormí poco, me costó concentrarme.",
"Necesito mejorar mi regulación emocional ante el estrés.",
"Gran día de trabajo profundo, la memoria funcionó genial.",
"Me costó levantarme, pero cumplí con mis hábitos.",
"Día tranquilo, dediqué tiempo a socializar y me sentí bien.",
"El ejercicio me cambió el ánimo radicalmente.",
"Mucha ansiedad por la mañana, pero la controlé.",
"Agradecido por mi familia y amigos.",
"Logré terminar el proyecto pendiente, concentración al 100."
];

// ==========================================
// 3. VISTA DE COMENTARIOS MENSUALES
// ==========================================

function MonthlyReflections({ onBack, user, onAuthRequest }) {
const [rawData, setRawData] = useState([]);
const [loading, setLoading] = useState(true);
const [selectedMonth, setSelectedMonth] = useState(null);
const [availableMonths, setAvailableMonths] = useState([]);

useEffect(() => {
if (!user) {
setLoading(false);
return;
}
const fetchHistory = async () => {
setLoading(true);
try {
if (!db) throw new Error("No db");
const snapshot = await getDocs(collection(db, 'artifacts', appId, 'users', user.uid, 'daily_logs'));
const historyData = [];
snapshot.forEach(doc => historyData.push(doc.data()));
historyData.sort((a, b) => new Date(a.fecha) - new Date(b.fecha));
setRawData(historyData);
const months = [...new Set(historyData.map(d => getMonthName(d.fecha)))];
setAvailableMonths(months);
if (months.length > 0) setSelectedMonth(months[months.length - 1]);
} catch (error) { console.error(error); } finally { setLoading(false); }
};
fetchHistory();
}, [user]);

const filteredData = useMemo(() => {
if (!selectedMonth) return [];
return rawData.filter(d => getMonthName(d.fecha) === selectedMonth);
}, [rawData, selectedMonth]);

if (loading) return <div className="min-h-screen bg-slate-50 text-slate-800 flex items-center justify-center gap-3"><Loader2 className="animate-spin text-indigo-600"/> Cargando diario...</div>;

return (
<div className="min-h-screen bg-slate-50 text-slate-800 font-sans pb-10">
<CompanyHeader darkMode={false} onAuthClick={onAuthRequest} user={user} />
<div className="max-w-3xl mx-auto px-4 py-6">
<div className="flex flex-col md:flex-row justify-between items-center gap-4 mb-8">
<div className="flex items-center gap-4 w-full md:w-auto">
<button onClick={onBack} className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-600"><ArrowLeft size={24} /></button>
<h1 className="text-xl font-bold tracking-tight text-slate-900">Diario de Reflexiones</h1>
</div>
{availableMonths.length > 0 && (
<div className="relative group w-full md:w-auto">
<select value={selectedMonth || ''} onChange={(e) => setSelectedMonth(e.target.value)} className="appearance-none w-full md:w-48 bg-slate-100 border border-slate-300 text-slate-700 pl-4 pr-10 py-2 rounded-lg text-sm font-medium focus:outline-none focus:ring-2 focus:ring-indigo-500 cursor-pointer capitalize">
{availableMonths.map(m => <option key={m} value={m}>{m}</option>)}
</select>
<ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 pointer-events-none" size={16} />
</div>
)}
</div>

<div className="space-y-6">
{filteredData.length === 0 ? (
