function PersonalDevDashboard({ onBack, user, onNavigateToComments, onAuthRequest }) {
const [rawData, setRawData] = useState([]);
const [loading, setLoading] = useState(true);
const [populating, setPopulating] = useState(false);
const [selectedMonth, setSelectedMonth] = useState(null);
const [availableMonths, setAvailableMonths] = useState([]);

// States for Charts
const [showMood, setShowMood] = useState(true);
const [showSleep, setShowSleep] = useState(true);
const [showEnergy, setShowEnergy] = useState(true);
const [showSocial, setShowSocial] = useState(true);
const [showMotivation, setShowMotivation] = useState(true);
const [showConcentration, setShowConcentration] = useState(true);
const [showRegulation, setShowRegulation] = useState(true);

// States for History
const [showHistoryMood, setShowHistoryMood] = useState(true);
const [showHistorySleep, setShowHistorySleep] = useState(false);
const [showHistoryEnergy, setShowHistoryEnergy] = useState(false);
const [showHistorySocial, setShowHistorySocial] = useState(false);
const [showHistoryMotivation, setShowHistoryMotivation] = useState(false);
const [showHistoryConcentration, setShowHistoryConcentration] = useState(false);
const [showHistoryRegulation, setShowHistoryRegulation] = useState(false);
const [showHistoryProgress, setShowHistoryProgress] = useState(true);

const fetchHistory = async () => {
if (!user) {
setLoading(false);
return;
}
setLoading(true);
try {
if(!db) throw new Error("No db");
const snapshot = await getDocs(collection(db, 'artifacts', appId, 'users', user.uid, 'daily_logs'));
const historyData = [];
snapshot.forEach(doc => historyData.push(doc.data()));
historyData.sort((a, b) => new Date(a.fecha) - new Date(b.fecha));
setRawData(historyData);
const months = [...new Set(historyData.map(d => getMonthName(d.fecha)))];
setAvailableMonths(months);
if (months.length > 0) {
if (!selectedMonth || !months.includes(selectedMonth)) setSelectedMonth(months[months.length - 1]);
}
} catch (error) { console.error(error); } finally { setLoading(false); }
};

useEffect(() => { if (user) fetchHistory(); }, [user]);

const data = useMemo(() => {
if (!selectedMonth) return rawData;
return rawData.filter(d => getMonthName(d.fecha) === selectedMonth);
}, [rawData, selectedMonth]);

const populateDemoData = async () => {
if (!user || !db) return;
setPopulating(true);
const batch = writeBatch(db);
const monthsToGenerate = [{ monthIndex: 8, days: 30 }, { monthIndex: 9, days: 31 }, { monthIndex: 10, days: 30 }];

for (const m of monthsToGenerate) {
for (let day = 1; day <= m.days; day++) {
const monthStr = (m.monthIndex + 1).toString().padStart(2, '0');
const dayStr = day.toString().padStart(2, '0');
const dateStr = `2025-${monthStr}-${dayStr}`;
const isWeekend = new Date(2025, m.monthIndex, day).getDay() % 6 === 0;
const moodBase = isWeekend ? 70 : 60;

const mood = Math.min(100, Math.max(0, Math.floor(Math.random() * 30) + moodBase));
const sleep = Math.min(100, Math.max(0, Math.floor(Math.random() * 40) + 50));
const energy = Math.min(100, Math.max(0, Math.floor(Math.random() * 40) + (isWeekend ? 50 : 40)));
const social = Math.min(100, Math.max(0, Math.floor(Math.random() * 50) + (isWeekend ? 50 : 20)));
const motivation = Math.min(100, Math.max(0, Math.floor(Math.random() * 40) + (energy * 0.5) + 10));
const concentration = Math.min(100, Math.max(0, Math.floor(Math.random() * 40) + (sleep * 0.4) + 20));
const regulation = Math.min(100, Math.max(0, Math.floor(Math.random() * 30) + 50));
const goalsCount = Math.floor(Math.random() * 5) + 3;
const progress = Math.round((goalsCount / DEFAULT_GOALS.length) * 100);

const docRef = doc(db, 'artifacts', appId, 'users', user.uid, 'daily_logs', dateStr);
batch.set(docRef, {
fecha: dateStr, timestamp: Date.now(), estado_animo: mood, calidad_sueno: sleep, nivel_energia: energy, social_confort: social, nivel_motivacion: motivation, nivel_concentracion: concentration, regulacion_emocional: regulation, reflexion: REFLECTIONS_MOCK[Math.floor(Math.random() * REFLECTIONS_MOCK.length)], progreso_porcentaje: progress, objetivos_completados: [], objetivos_pendientes: []
});
}
}
try { await batch.commit(); await fetchHistory(); setSelectedMonth("noviembre de 2025"); } catch (e) { console.error(e); } finally { setPopulating(false); }
};

const stats = useMemo(() => {
if (data.length === 0) return { avgMood: 0, avgSleep: 0, avgEnergy: 0, avgSocial: 0, avgMotiv: 0, avgConc: 0, avgReg: 0, avgProgress: 0 };
