function PersonalCanvas({ onNavigateToDashboard, onNavigateToComments, currentDate, onDateChange, user, onAuthRequest }) {
const [goals, setGoals] = useState(DEFAULT_GOALS);
const [reflection, setReflection] = useState("");
const [mood, setMood] = useState(50);
const [sleepQuality, setSleepQuality] = useState(50);
const [energyLevel, setEnergyLevel] = useState(50);
const [socialLevel, setSocialLevel] = useState(50);
const [motivationLevel, setMotivationLevel] = useState(50);
const [concentrationLevel, setConcentrationLevel] = useState(50);
const [regulationLevel, setRegulationLevel] = useState(50);

const [activeResource, setActiveResource] = useState(null);
const [isSaving, setIsSaving] = useState(false);
const [toast, setToast] = useState(null);
const [showResetConfirm, setShowResetConfirm] = useState(false);

const isToday = useMemo(() => {
const today = new Date();
const year = today.getFullYear();
const month = String(today.getMonth() + 1).padStart(2, '0');
const day = String(today.getDate()).padStart(2, '0');
return currentDate === `${year}-${month}-${day}`;
}, [currentDate]);

const isGuest = !user || user.isAnonymous;

useEffect(() => {
if (!user) return;
const loadDay = async () => {
try {
const docSnap = await getDoc(doc(db, 'artifacts', appId, 'users', user.uid, 'daily_logs', currentDate));
if (docSnap.exists()) {
const d = docSnap.data();
setMood(d.estado_animo || 50);
setEnergyLevel(d.nivel_energia || 50);
setSleepQuality(d.calidad_sueno || 50);
setSocialLevel(d.social_confort || 50);
setMotivationLevel(d.nivel_motivacion || 50);
setConcentrationLevel(d.nivel_concentracion || 50);
setRegulationLevel(d.regulacion_emocional || 50);
setReflection(d.reflexion || "");
const completed = d.objetivos_completados?.map(t => t.tarea) || [];
setGoals(DEFAULT_GOALS.map(g => ({...g, completed: completed.includes(g.text)})));
} else {
setGoals(DEFAULT_GOALS.map(g => ({...g, completed: false})));
setReflection("");
setMood(50);
setEnergyLevel(50);
setSleepQuality(50);
setSocialLevel(50);
setMotivationLevel(50);
setConcentrationLevel(50);
setRegulationLevel(50);
}
} catch(e) { console.error(e); }
};
loadDay();
}, [currentDate, user]);

const toggleGoal = (id) => {
setGoals(goals.map(goal => goal.id === id ? { ...goal, completed: !goal.completed } : goal));
};

const openResource = (goal) => {
const key = goal.resourceKey || 'general';
const resourceData = RESOURCES_DB[key] || RESOURCES_DB['general'];
if (key === 'reading') {
const randomBook = resourceData[Math.floor(Math.random() * resourceData.length)];
setActiveResource({ task: goal.text, type: 'book_recommendation', data: randomBook });
} else if (Array.isArray(resourceData)) {
setActiveResource({ task: goal.text, type: 'list', data: resourceData });
} else {
setActiveResource({ task: goal.text, type: 'tip', data: resourceData });
}
};

const saveDailyRecord = async () => {
if (isGuest) return; // Prevent action if guest

setIsSaving(true);
const exportObject = {
fecha: currentDate,
timestamp: Date.now(),
estado_animo: mood,
nivel_energia: energyLevel,
calidad_sueno: sleepQuality,
social_confort: socialLevel,
nivel_motivacion: motivationLevel,
nivel_concentracion: concentrationLevel,
regulacion_emocional: regulationLevel,
reflexion: reflection,
progreso_porcentaje: Math.round((goals.filter(g => g.completed).length / goals.length) * 100),
objetivos_completados: goals.filter(g => g.completed).map(g => ({ tarea: g.text, categoria: g.category })),
objetivos_pendientes: goals.filter(g => !g.completed).map(g => ({ tarea: g.text, categoria: g.category }))
};

try {
await setDoc(doc(db, 'artifacts', appId, 'users', user.uid, 'daily_logs', currentDate), exportObject);
setToast({ message: isToday ? "¡Guardado en la Nube!" : "Corrección Guardada", type: 'success' });
} catch (e) {
console.error(e);
setToast({ message: "Error al guardar", type: 'error' });
} finally {
setIsSaving(false);
}
};

const handleReset = () => {
setGoals(DEFAULT_GOALS.map(g => ({...g, completed: false})));
setShowResetConfirm(false);
setToast({ message: "Día reiniciado", type: 'success' });
};

const progress = Math.round((goals.filter(g => g.completed).length / goals.length) * 100);

